mapper.select:
SELECT t.id, t.user_id, t.resume_id, t.jd_id, t.request_type, t.status, t.create_time FROM tb_resume_analysis t LEFT JOIN tb_resume r ON t.resume_id = r.id LEFT JOIN tb_jd j ON t.jd_id = j.id
AND CAST(t.id AS CHAR) LIKE CONCAT('%', #{condition.id}, '%')
AND CAST(t.user_id AS CHAR) LIKE CONCAT('%', #{condition.userId}, '%')
AND SUBSTRING_INDEX( SUBSTRING_INDEX( REPLACE(r.file_path, '\\', '/'), '/', -1), '_', 1 ) LIKE CONCAT('%', #{condition.resumeKeyword}, '%')
AND ( j.title LIKE CONCAT('%', #{condition.jdKeyword}, '%') OR j.company LIKE CONCAT('%', #{condition.jdKeyword}, '%') OR j.location LIKE CONCAT('%', #{condition.jdKeyword}, '%') OR SUBSTRING_INDEX( SUBSTRING_INDEX( REPLACE(j.file_path, '\\', '/'), '/', -1), '_', 1 ) LIKE CONCAT('%', #{condition.jdKeyword}, '%') )
AND t.request_type IN
#{item}
AND t.status IN
#{item}
AND t.create_time >= #{condition.startCreateTime}
AND t.create_time <= #{condition.endCreateTime}
ORDER BY t.create_time DESC
